fn write_for_loop(&mut self, forloop: &ForLoop) -> std::fmt::Result {
    // Use the original source text for the pattern to preserve spacing
    // (avoiding extra spaces that TokenStream inserts around punctuation)
    let pat_str = forloop
        .pat
        .span()
        .source_text()
        .unwrap_or_else(|| forloop.pat.clone().into_token_stream().to_string());

    write!(self.out, "for {} in ", pat_str)?;

    self.write_inline_expr(&forloop.expr)?;

    if forloop.body.is_empty() {
        write!(self.out, "}}")?;
        return Ok(());
    }

    self.out.new_line()?;
    self.write_body_indented(&forloop.body.roots)?;
